window.LEARNPROJECTS = [{"schemaVersion":"1.0","slug":"techwatch","title":"TechWatch IA","goal":"Construire une plateforme de veille technologique assistée par IA produisant des synthèses de migration fiables, sourcées et vérifiables.","summary":"Le différenciateur du projet est la confiance : chaque affirmation cite sa source. L'architecture est un workflow LLM déterministe, eval-driven, long-context d'abord (zéro RAG au MVP), avec relecture humaine. Ce projet rassemble les leçons d'ingénierie IA mobilisées, reliées aux packs de la bibliothèque. Le curriculum complet (20 sujets) est désormais disponible en packs groundés ci-dessous.","tags":["veille","llm","rag","eval","architecture"],"status":"actif","externalCurriculum":"techwatch/","path":[{"packSlug":"workflow-deterministe-vs-agents","why":"Le cœur : orchestrer 9 étapes plutôt que des agents autonomes."},{"packSlug":"long-context-rag-fine-tuning","why":"Pourquoi le MVP est long-context, pas RAG."},{"packSlug":"prompt-engineering-sorties-structurees","why":"Sorties structurées + citations à chaque appel LLM."},{"packSlug":"grounding-anti-hallucination","why":"Règles 1 & 2 : citations obligatoires, « null si absent »."},{"packSlug":"eval-driven-development","why":"Golden set + assertions déterministes = la porte qualité."},{"packSlug":"llm-as-judge","why":"Compléter l’éval hors chemin critique."},{"packSlug":"guardrails","why":"Garde-fous en couches avant publication."},{"packSlug":"human-in-the-loop","why":"Règle 3 : relecture humaine en gate."},{"packSlug":"securite-llm-owasp","why":"Le contenu collecté = donnée non fiable (prompt injection)."},{"packSlug":"finops-ia-couts","why":"Coût/synthèse maîtrisé : prompt caching, model routing."},{"packSlug":"observabilite-llm","why":"Mesurer coût & qualité dès le jour 1."},{"packSlug":"detection-de-version","why":"Le déclencheur : polling GitHub + ETags."},{"packSlug":"collecte-api-first-extraction","why":"Récupérer les sources officielles : API-first."},{"packSlug":"ssrf-allowlist-crawler","why":"Sécuriser le crawler : allowlist de domaines."},{"packSlug":"monolithe-modulaire-ddd","why":"Architecture : monolithe modulaire + workers."},{"packSlug":"serverless-event-driven","why":"Charge bursty → serverless scale-to-zero."},{"packSlug":"notifications-fan-out-idempotence","why":"Notifier les abonnés : fan-out idempotent."},{"packSlug":"choix-gestion-modeles","why":"Choisir/piloter les modèles (Haiku/Sonnet/Opus)."},{"packSlug":"provenance-versionnement-contenu","why":"Provenance + versionnement = audit trail."},{"packSlug":"right-sizing-yagni","why":"Le fil rouge : éviter l’over-engineering."}],"lessons":[{"title":"Règle 1 — Citations obligatoires","body":"Chaque affirmation d'une synthèse pointe sa source officielle (URL + section). Une affirmation non sourçable est retirée.","decision":"Grounding vérifié verbatim comme invariant.","packs":["grounding-anti-hallucination"]},{"title":"Règle 2 — « null si absent »","body":"Interdiction d'inventer une version, une API ou un breaking change : pas dans les sources → null, signalé.","decision":"Anti-hallucination par contrainte de sortie.","packs":["grounding-anti-hallucination","guardrails"]},{"title":"Règle 3 — Relecture humaine","body":"Aucune synthèse n'est diffusée sans validation humaine ; le bloc 2 la fait passer de 100 % à un échantillonnage ciblé.","decision":"Human-in-the-loop en gate de publication.","packs":["human-in-the-loop","eval-driven-development"]},{"title":"Workflow déterministe, pas d'agents","body":"Les 9 étapes du pipeline sont connues et ordonnées : on orchestre des étapes, on ne délègue pas à des agents autonomes.","decision":"Pipeline décomposé et évaluable.","packs":["workflow-deterministe-vs-agents"]},{"title":"Long-context d'abord","body":"Le corpus d'une transition de version tient dans la fenêtre : zéro base vectorielle au MVP.","decision":"RAG seulement si un besoin de recherche est prouvé.","packs":["long-context-rag-fine-tuning"]},{"title":"Éval = la nouvelle porte qualité","body":"Un golden set + des assertions déterministes bloquent la publication ; le LLM-judge complète hors chemin critique.","decision":"Eval-driven development.","packs":["eval-driven-development","llm-as-judge"]}]}];
